solution: ```class Solution {
public:
    int strongPasswordChecker(string s) {
        int n = s.size();
        bool hasLower = false, hasUpper = false, hasDigit = false;
        for (char c : s) {
            if (islower(c)) hasLower = true;
            else if (isupper(c)) hasUpper = true;
            else if (isdigit(c)) hasDigit = true;
        }
        int missingTypes = (!hasLower) + (!hasUpper) + (!hasDigit);

        int replace = 0, one = 0, two = 0;
        for (int i = 2; i < n; ) {
            if (s[i] == s[i-1] && s[i-1] == s[i-2]) {
                int len = 2;
                while (i < n && s[i] == s[i-1]) { len++; i++; }
                replace += len / 3;
                if (len % 3 == 0) one++;
                else if (len % 3 == 1) two++;
            } else {
                i++;
            }
        }

        if (n < 6) {
            return max(6 - n, missingTypes);
        } else if (n <= 20) {
            return max(replace, missingTypes);
        } else {
            int deleteCount = n - 20;
            replace -= min(deleteCount, one * 1) / 1;
            replace -= min(max(deleteCount - one, 0), two * 2) / 2;
            replace -= max(deleteCount - one - 2 * two, 0) / 3;
            return deleteCount + max(replace, missingTypes);
        }
    }
};
```
